// ============================================================
// SECURITY + VALIDATION LAYER
// 1) Verify HMAC-SHA256 signature so only trusted senders pass
// 2) Validate required fields and email format
// 3) Sanitize input (trim, strip control chars, cap lengths)
// No secrets are logged anywhere in this node.
// ============================================================
const crypto = require('crypto');

// Shared secret comes from an environment variable, never hardcoded.
// Set N8N_LEAD_HMAC_SECRET in your n8n environment (.env).
const SECRET = $env.N8N_LEAD_HMAC_SECRET || '';

const item = $input.first();
const headers = (item.json.headers) || {};
const body = (item.json.body) || {};

// Raw body string for signature verification (set rawBody:true on webhook).
let rawBody = '';
if (typeof item.json.body === 'string') {
  rawBody = item.json.body;
} else {
  rawBody = JSON.stringify(body);
}

function fail(reason, code) {
  return [{ json: { ok: false, stage: 'verify', error: reason, httpCode: code } }];
}

// ---- 1) Signature check ----
// If a secret is configured, the request MUST carry a valid signature.
if (SECRET) {
  const provided = (headers['x-signature'] || headers['X-Signature'] || '').toString();
  if (!provided) {
    return fail('missing_signature', 401);
  }
  const expected = crypto.createHmac('sha256', SECRET).update(rawBody).digest('hex');
  // Constant-time compare to avoid timing leaks.
  const a = Buffer.from(expected);
  const b = Buffer.from(provided);
  if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
    return fail('invalid_signature', 401);
  }
}

// ---- 2) Parse body if it arrived as a raw string ----
let data = body;
if (typeof body === 'string') {
  try { data = JSON.parse(body); } catch (e) { return fail('invalid_json', 400); }
}

// ---- 3) Field validation ----
const name = (data.name || '').toString();
const email = (data.email || '').toString();
const company = (data.company || '').toString();
const message = (data.message || '').toString();

if (!name.trim() || !email.trim() || !message.trim()) {
  return fail('missing_required_fields', 400);
}

const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
if (!emailOk) {
  return fail('invalid_email', 400);
}

// ---- 4) Sanitization ----
// Strip control characters, collapse whitespace, cap lengths.
// Capping the message length also limits prompt-injection surface.
function clean(s, max) {
  return s
    .replace(/[\u0000-\u001F\u007F]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, max);
}

const safe = {
  name: clean(name, 120),
  email: clean(email, 200).toLowerCase(),
  company: clean(company, 160),
  message: clean(message, 2000)
};

return [{ json: { ok: true, lead: safe, receivedAt: new Date().toISOString() } }];

// ============================================================
// ENRICHMENT
// Derive light signal from the email domain without any
// external paid lookup. Flags free vs business email.
// ============================================================
const lead = $input.first().json.lead;
const domain = lead.email.split('@')[1] || '';

const freeProviders = ['gmail.com','yahoo.com','hotmail.com','outlook.com','aol.com','icloud.com','proton.me','protonmail.com','gmx.com','mail.com'];
const isFreeEmail = freeProviders.includes(domain);

return [{
  json: {
    lead,
    enrichment: {
      domain,
      isFreeEmail,
      emailType: isFreeEmail ? 'personal' : 'business'
    },
    receivedAt: $input.first().json.receivedAt
  }
}];

