// ============================================================
// PARSE + GUARD the model output.
// Never trust the model blindly: parse defensively, validate
// the shape, clamp the score, and fall back to manual review
// if anything is off.
// ============================================================
const input = $input.first().json;
let text = '';

try {
  // Anthropic returns { content: [ { type:'text', text:'...' } ] }
  if (input.content && Array.isArray(input.content)) {
    text = input.content.map(c => c.text || '').join('');
  } else if (typeof input.text === 'string') {
    text = input.text;
  }
} catch (e) {
  text = '';
}

function fallback(reason) {
  return {
    score: 50,
    tier: 'warm',
    reason: 'Auto-fallback: ' + reason,
    suggested_reply: 'Thank you for reaching out. A member of our team will review your message and get back to you shortly.',
    parsed_ok: false
  };
}

let parsed;
try {
  // Strip any accidental code fences before parsing.
  const cleaned = text.replace(/```json/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = fallback('unparseable_model_output');
}

// Validate + clamp.
let score = Number(parsed.score);
if (!Number.isFinite(score)) score = 50;
score = Math.max(0, Math.min(100, Math.round(score)));

let tier = (parsed.tier || '').toString().toLowerCase();
if (!['hot','warm','cold'].includes(tier)) {
  // Derive tier from score if the model gave a bad value.
  tier = score >= 75 ? 'hot' : score >= 45 ? 'warm' : 'cold';
}

const reason = (parsed.reason || 'No reason provided').toString().slice(0, 300);
const suggested_reply = (parsed.suggested_reply || 'Thank you for reaching out. We will be in touch soon.').toString().slice(0, 1000);

// Pull the original lead/enrichment forward from the node before the HTTP call.
const src = $('Build Enrichment').first().json;

return [{
  json: {
    lead: src.lead,
    enrichment: src.enrichment,
    receivedAt: src.receivedAt,
    scoring: { score, tier, reason, suggested_reply, parsed_ok: parsed.parsed_ok !== false }
  }
}];

// ============================================================
// ERROR-OUTPUT BRANCH for the Claude HTTP call.
// If the API failed after all retries, do NOT drop the lead.
// Mark it for manual review and continue so it still gets
// logged and alerted.
// ============================================================
const src = $('Build Enrichment').first().json;

return [{
  json: {
    lead: src.lead,
    enrichment: src.enrichment,
    receivedAt: src.receivedAt,
    scoring: {
      score: 50,
      tier: 'warm',
      reason: 'Scoring API unavailable, routed to manual review',
      suggested_reply: 'Thank you for reaching out. A member of our team will review your message and get back to you shortly.',
      parsed_ok: false,
      api_failed: true
    }
  }
}];

