// ============================================================
// Build the audit row. Records what happened for traceability.
// Deliberately excludes any secrets, keys, or signatures.
// ============================================================
const j = $input.first().json;
const lead = j.lead || {};
const enr = j.enrichment || {};
const sc = j.scoring || {};

return [{
  json: {
    timestamp: new Date().toISOString(),
    name: lead.name || '',
    email: lead.email || '',
    company: lead.company || '',
    email_type: enr.emailType || '',
    domain: enr.domain || '',
    score: sc.score != null ? sc.score : '',
    tier: sc.tier || '',
    reason: sc.reason || '',
    parsed_ok: sc.parsed_ok === true,
    api_failed: sc.api_failed === true,
    message: lead.message || ''
  }
}];

// ============================================================
// Collects failures from Slack / Email / Sheets error outputs
// so a downstream step can alert without dropping the lead.
// ============================================================
const j = $input.first().json;
return [{
  json: {
    failedNode: ($node && $node.name) ? $node.name : 'unknown',
    leadEmail: (j.lead && j.lead.email) || (j.email) || 'unknown',
    note: 'A delivery/logging step failed. Lead was still processed.',
    at: new Date().toISOString()
  }
}];
